UPDATE driver
name = #{name}, gender = #{gender}, age = #{age}, phone = #{phone}, line_id = #{lineId}, is_road_captain = #{isRoadCaptain}, is_captain = #{isCaptain}, hire_date = #{hireDate},
WHERE driver_id = #{driverId}

mapper.select:
SELECT d.driver_id, d.name, d.gender, d.age, d.phone, d.line_id, l.line_name, f.fleet_name, d.is_road_captain, d.is_captain, d.hire_date FROM driver d LEFT JOIN line l ON d.line_id = l.line_id LEFT JOIN fleet f ON (l.fleet_id = f.fleet_id OR f.captain_id = d.driver_id)
AND (d.name LIKE CONCAT('%', #{keyword}, '%') OR d.driver_id LIKE CONCAT('%', #{keyword}, '%'))
AND d.line_id = #{lineId}
AND l.fleet_id = #{fleetId}
AND d.gender = #{gender}
ORDER BY d.hire_date DESC
